import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { TranslateService } from '@ngx-translate/core';
import { RevenueService, RevenueItem } from '../../services/revenue.service';
import { CategoryService, Category } from '../../services/category.service';
import { TableGroupingService, GroupedData } from '../../shared/table-grouping.service';

@Component({
  selector: 'app-revenue',
  templateUrl: './revenue.component.html',
  styleUrls: ['./revenue.component.css']
})
export class RevenueComponent implements OnInit {
  revenueItems: RevenueItem[] = [];
  filteredItems: RevenueItem[] = [];
  groupedData: GroupedData<RevenueItem>[] = [];
  groupByField: string = 'none';
  showForm = false;
  editingItem: RevenueItem | null = null;
  searchTerm = '';
  loading = false;
  error: string | null = null;

  // Categories
  revenueCategories: Category[] = [];

  // Date filtering
  selectedYear: number = new Date().getFullYear();
  selectedMonth: number = new Date().getMonth();
  viewMode: 'all' | 'yearly' | 'monthly' | 'daily' = 'all';
  availableYears: number[] = [];
  availableMonths: string[] = [];

  revenueForm: FormGroup;

  constructor(
    private revenueService: RevenueService,
    private categoryService: CategoryService,
    private fb: FormBuilder,
    private translate: TranslateService
  ) {
    this.revenueForm = this.fb.group({
      date: ['', Validators.required],
      source: ['', Validators.required],
      amount: ['', [Validators.required, Validators.min(0)]],
      description: ['']
    });
  }

  ngOnInit(): void {
    this.generateAvailableYears();
    this.loadMonths();
    this.loadCategories();
    this.loadRevenue();
    
    // Reload months when language changes
    this.translate.onLangChange.subscribe(() => {
      this.loadMonths();
      this.applyGrouping(); // Re-translate group values
    });
  }

  loadCategories(): void {
    this.categoryService.getCategoriesByType('revenue').subscribe({
      next: (data) => {
        this.revenueCategories = data;
      },
      error: (error) => {
        console.error('Error loading revenue categories:', error);
      }
    });
  }

  getCategoryName(category: Category): string {
    const currentLang = this.translate.currentLang;
    return currentLang === 'ar' ? category.name_ar : category.name_en;
  }

  loadMonths(): void {
    this.availableMonths = [
      this.translate.instant('MONTHS.JANUARY'),
      this.translate.instant('MONTHS.FEBRUARY'),
      this.translate.instant('MONTHS.MARCH'),
      this.translate.instant('MONTHS.APRIL'),
      this.translate.instant('MONTHS.MAY'),
      this.translate.instant('MONTHS.JUNE'),
      this.translate.instant('MONTHS.JULY'),
      this.translate.instant('MONTHS.AUGUST'),
      this.translate.instant('MONTHS.SEPTEMBER'),
      this.translate.instant('MONTHS.OCTOBER'),
      this.translate.instant('MONTHS.NOVEMBER'),
      this.translate.instant('MONTHS.DECEMBER')
    ];
  }

  generateAvailableYears(): void {
    const currentYear = new Date().getFullYear();
    this.availableYears = [];
    for (let year = currentYear - 5; year <= currentYear + 1; year++) {
      this.availableYears.push(year);
    }
  }

  loadRevenue(): void {
    this.loading = true;
    this.error = null;
    this.revenueService.getAllRevenue().subscribe({
      next: (data) => {
        this.revenueItems = data;
        this.applyFilters();
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load revenue data';
        this.loading = false;
        console.error('Error loading revenue:', error);
      }
    });
  }

  applyFilters(): void {
    let filtered = [...this.revenueItems];

    // Apply search filter
    if (this.searchTerm.trim()) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(item =>
        item.source.toLowerCase().includes(term) ||
        item.description?.toLowerCase().includes(term) ||
        item.amount.toString().includes(term)
      );
    }

    // Apply date filters based on view mode
    if (this.viewMode === 'yearly') {
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        const itemYear = itemDate.getFullYear();
        return itemYear === this.selectedYear;
      });
    } else if (this.viewMode === 'monthly') {
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        const itemYear = itemDate.getFullYear();
        const itemMonth = itemDate.getMonth();
        return itemYear === this.selectedYear && itemMonth === this.selectedMonth;
      });
    } else if (this.viewMode === 'daily') {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        itemDate.setHours(0, 0, 0, 0);
        return itemDate.getTime() === today.getTime();
      });
    }

    this.filteredItems = filtered;
    this.applyGrouping();
  }

  applyGrouping(): void {
    this.groupedData = TableGroupingService.groupBy(this.filteredItems, this.groupByField);
    // Translate group values
    if (this.groupByField === 'source') {
      this.groupedData.forEach(group => {
        group.groupValue = this.translate.instant('REVENUE.SOURCES.' + group.groupKey.toUpperCase());
      });
    } else if (this.groupByField === 'date') {
      this.groupedData.forEach(group => {
        if (group.groupKey !== 'all') {
          const date = new Date(group.groupKey);
          const day = String(date.getDate()).padStart(2, '0');
          const month = String(date.getMonth() + 1).padStart(2, '0');
          const year = date.getFullYear();
          group.groupValue = `${day}/${month}/${year}`;
        }
      });
    }
  }

  onGroupByChange(): void {
    this.applyGrouping();
  }

  toggleGroup(group: GroupedData<RevenueItem>): void {
    group.expanded = !group.expanded;
  }

  expandAll(): void {
    this.groupedData.forEach(group => group.expanded = true);
  }

  collapseAll(): void {
    this.groupedData.forEach(group => group.expanded = false);
  }

  onSearch(): void {
    this.applyFilters();
  }

  onViewModeChange(): void {
    this.applyFilters();
  }

  onYearChange(): void {
    this.applyFilters();
  }

  onMonthChange(): void {
    this.applyFilters();
  }

  openAddForm(): void {
    this.editingItem = null;
    this.revenueForm.reset();
    const today = new Date();
    const day = String(today.getDate()).padStart(2, '0');
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const year = today.getFullYear();
    this.revenueForm.patchValue({
      date: `${year}-${month}-${day}`
    });
    this.showForm = true;
  }

  editItem(item: RevenueItem): void {
    this.editingItem = item;
    this.revenueForm.patchValue({
      date: item.date,
      source: item.source,
      amount: item.amount,
      description: item.description || ''
    });
    this.showForm = true;
  }

  cancelForm(): void {
    this.showForm = false;
    this.editingItem = null;
    this.revenueForm.reset();
  }

  onSubmit(): void {
    if (this.revenueForm.valid) {
      const formValue = this.revenueForm.value;

      if (this.editingItem) {
        // Update existing item
        this.revenueService.updateRevenue(this.editingItem.id!, formValue).subscribe({
          next: () => {
            this.loadRevenue();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to update revenue item';
            console.error('Error updating revenue:', error);
          }
        });
      } else {
        // Create new item
        this.revenueService.createRevenue(formValue).subscribe({
          next: () => {
            this.loadRevenue();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to create revenue item';
            console.error('Error creating revenue:', error);
          }
        });
      }
    } else {
      this.revenueForm.markAllAsTouched();
    }
  }

  deleteItem(item: RevenueItem): void {
    if (confirm(`Are you sure you want to delete this ${item.source} revenue entry?`)) {
      this.revenueService.deleteRevenue(item.id!).subscribe({
        next: () => {
          this.loadRevenue();
        },
        error: (error) => {
          this.error = 'Failed to delete revenue item';
          console.error('Error deleting revenue:', error);
        }
      });
    }
  }

  getTotalRevenue(): number {
    return this.filteredItems.reduce((total, item) => total + item.amount, 0);
  }

  getFormFieldError(fieldName: string): string {
    const field = this.revenueForm.get(fieldName);
    if (field?.errors && field.touched) {
      if (field.errors['required']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} is required`;
      }
      if (field.errors['min']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} must be positive`;
      }
    }
    return '';
  }

  trackById(index: number, item: RevenueItem): string {
    return item.id || index.toString();
  }

  getSourceClass(source: string): string {
    return 'source-' + source.toLowerCase().replace(/\s+/g, '-');
  }
}
<div class="revenue-page">
  <div class="page-header">
    <div>
      <h1>{{ 'REVENUE.TITLE' | translate }}</h1>
      <p>{{ 'REVENUE.SUBTITLE' | translate }}</p>
    </div>
    <div class="header-actions">
      <a routerLink="/dashboard" class="btn btn-secondary">{{ 'NAV.DASHBOARD' | translate }}</a>
      <button (click)="openAddForm()" class="btn btn-add">
        <span class="icon">➕</span>
        {{ 'REVENUE.ADD_REVENUE' | translate }}
      </button>
    </div>
  </div>

  <!-- Error Message -->
  <div *ngIf="error" class="alert alert-error">
    <span>⚠️</span>
    {{ error }}
    <button (click)="error = null" class="alert-close">×</button>
  </div>

  <!-- Stats Card -->
  <div class="stats-card">
    <div class="stat-item">
      <div class="stat-label">{{ 'REVENUE.TOTAL_REVENUE' | translate }}</div>
      <div class="stat-value">${{ getTotalRevenue() | number:'1.0-0' }}</div>
    </div>
    <div class="stat-item">
      <div class="stat-label">{{ 'REVENUE.FILTERED_ENTRIES' | translate }}</div>
      <div class="stat-value">{{ filteredItems.length }}</div>
    </div>
  </div>

  <!-- Search and Filters -->
  <div class="filters-section">
    <div class="search-box">
      <input
        type="text"
        [placeholder]="'REVENUE.SEARCH_PLACEHOLDER' | translate"
        [(ngModel)]="searchTerm"
        (input)="onSearch()"
        class="form-input">
      <span class="search-icon">🔍</span>
    </div>

    <div class="date-filters">
      <div class="filter-group">
        <label>{{ 'FILTERS.VIEW_MODE' | translate }}:</label>
        <select [(ngModel)]="viewMode" (change)="onViewModeChange()" class="filter-select">
          <option value="all">{{ 'FILTERS.ALL_TIME' | translate }}</option>
          <option value="yearly">{{ 'FILTERS.YEARLY' | translate }}</option>
          <option value="monthly">{{ 'FILTERS.MONTHLY' | translate }}</option>
          <option value="daily">{{ 'FILTERS.DAILY' | translate }}</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'yearly' || viewMode === 'monthly'">
        <label>{{ 'FILTERS.YEAR' | translate }}:</label>
        <select [(ngModel)]="selectedYear" (ngModelChange)="onYearChange()" class="filter-select">
          <option *ngFor="let year of availableYears" [ngValue]="year">{{year}}</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'monthly'">
        <label>{{ 'FILTERS.MONTH' | translate }}:</label>
        <select [(ngModel)]="selectedMonth" (ngModelChange)="onMonthChange()" class="filter-select">
          <option *ngFor="let month of availableMonths; let i = index" [ngValue]="i">{{month}}</option>
        </select>
      </div>

      <div class="filter-group">
        <label>{{ 'FILTERS.GROUP_BY' | translate }}:</label>
        <select [(ngModel)]="groupByField" (ngModelChange)="onGroupByChange()" class="filter-select">
          <option value="none">{{ 'FILTERS.NO_GROUPING' | translate }}</option>
          <option value="source">{{ 'REVENUE.SOURCE' | translate }}</option>
          <option value="date">{{ 'COMMON.DATE' | translate }}</option>
        </select>
      </div>
    </div>
  </div>

  <!-- Revenue Form Modal -->
  <div *ngIf="showForm" class="modal-overlay" (click)="cancelForm()">
    <div class="modal-content" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h2>{{ (editingItem ? 'COMMON.EDIT' : 'COMMON.ADD') | translate }} {{ 'REVENUE.TITLE' | translate }}</h2>
        <button (click)="cancelForm()" class="modal-close">×</button>
      </div>

      <form [formGroup]="revenueForm" (ngSubmit)="onSubmit()" class="revenue-form">
        <div class="form-row">
          <div class="form-group">
            <label class="form-label">{{ 'COMMON.DATE' | translate }} *</label>
            <input
              type="date"
              formControlName="date"
              class="form-input"
              [class.error]="getFormFieldError('date')">
            <div *ngIf="getFormFieldError('date')" class="field-error">
              {{ getFormFieldError('date') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">{{ 'REVENUE.SOURCE' | translate }} *</label>
            <select formControlName="source" class="form-select" [class.error]="getFormFieldError('source')">
              <option value="">{{ 'FORM.SELECT_SOURCE' | translate }}</option>
              <option *ngFor="let category of revenueCategories" [value]="category.name_en">
                {{ getCategoryName(category) }}
              </option>
            </select>
            <div *ngIf="getFormFieldError('source')" class="field-error">
              {{ getFormFieldError('source') }}
            </div>
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label class="form-label">{{ 'COMMON.AMOUNT' | translate }} *</label>
            <div class="amount-input">
              <span class="currency-symbol">$</span>
              <input
                type="number"
                formControlName="amount"
                [placeholder]="'FORM.AMOUNT_PLACEHOLDER' | translate"
                step="0.01"
                min="0"
                class="form-input amount-field"
                [class.error]="getFormFieldError('amount')">
            </div>
            <div *ngIf="getFormFieldError('amount')" class="field-error">
              {{ getFormFieldError('amount') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">{{ 'COMMON.DESCRIPTION' | translate }}</label>
            <input
              type="text"
              formControlName="description"
              [placeholder]="'FORM.DESCRIPTION_PLACEHOLDER' | translate"
              class="form-input">
          </div>
        </div>

        <div class="form-actions">
          <button type="button" (click)="cancelForm()" class="btn btn-secondary">{{ 'COMMON.CANCEL' | translate }}</button>
          <button type="submit" [disabled]="!revenueForm.valid" class="btn btn-primary">
            {{ (editingItem ? 'COMMON.UPDATE' : 'COMMON.ADD') | translate }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Revenue Table -->
  <div class="card">
    <div class="card-header">
      <h2 class="card-title">{{ 'REVENUE.TITLE' | translate }}</h2>
      <div class="card-actions">
        <button (click)="loadRevenue()" class="btn btn-secondary btn-sm" [disabled]="loading">
          <span *ngIf="loading">⟳</span>
          <span *ngIf="!loading">🔄</span>
          {{ 'COMMON.REFRESH' | translate }}
        </button>
      </div>
    </div>

    <div class="card-content">
      <div *ngIf="loading" class="loading-state">
        <div class="loading-spinner">⟳</div>
        <p>{{ 'COMMON.LOADING' | translate }}...</p>
      </div>

      <div *ngIf="!loading && filteredItems.length === 0" class="empty-state">
        <div class="empty-icon">💰</div>
        <h3>{{ 'REVENUE.NO_ENTRIES' | translate }}</h3>
        <p>{{ searchTerm ? ('REVENUE.ADJUST_SEARCH' | translate) : ('REVENUE.ADD_FIRST' | translate) }}</p>
        <button *ngIf="!searchTerm" (click)="openAddForm()" class="btn btn-add">
          <span class="icon">➕</span>
          {{ 'COMMON.ADD' | translate }}
        </button>
      </div>

      <div *ngIf="!loading && filteredItems.length > 0" class="table-responsive">
        <div class="group-controls" *ngIf="groupByField !== 'none' && groupedData.length > 1">
          <button (click)="expandAll()" class="btn btn-secondary btn-sm">{{ 'COMMON.EXPAND_ALL' | translate }}</button>
          <button (click)="collapseAll()" class="btn btn-secondary btn-sm">{{ 'COMMON.COLLAPSE_ALL' | translate }}</button>
        </div>
        <div *ngFor="let group of groupedData" class="group-section">
          <div class="group-header" *ngIf="groupByField !== 'none'" (click)="toggleGroup(group)">
            <div class="group-header-left">
              <span class="group-toggle">{{ group.expanded ? '▼' : '▶' }}</span>
              <h3>{{ group.groupValue }}</h3>
              <span class="group-count">({{ group.items.length }} {{ 'COMMON.ITEMS' | translate }})</span>
            </div>
            <span class="group-total">${{ group.total | number:'1.2-2' }}</span>
          </div>
          <table class="table" *ngIf="group.expanded">
            <thead>
              <tr>
                <th>{{ 'COMMON.DATE' | translate }}</th>
                <th>{{ 'REVENUE.SOURCE' | translate }}</th>
                <th>{{ 'COMMON.DESCRIPTION' | translate }}</th>
                <th class="text-right">{{ 'COMMON.AMOUNT' | translate }}</th>
                <th class="text-center">{{ 'COMMON.ACTIONS' | translate }}</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let item of group.items; trackBy: trackById">
                <td>{{ item.date | customDate }}</td>
                <td>
                  <span class="source-badge" [ngClass]="getSourceClass(item.source)">
                    {{ 'REVENUE.SOURCES.' + item.source.toUpperCase() | translate }}
                  </span>
                </td>
                <td>{{ item.description || '-' }}</td>
                <td class="text-right">${{ item.amount | number:'1.2-2' }}</td>
                <td class="text-center">
                  <button (click)="editItem(item)" class="btn-action btn-edit" [title]="'COMMON.EDIT' | translate">
                    ✏️
                  </button>
                  <button (click)="deleteItem(item)" class="btn-action btn-delete" [title]="'COMMON.DELETE' | translate">
                    🗑️
                  </button>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>
</div>
